import Autumn from 'autumn-js';
import fs from 'fs';
import path from 'path';

// Initialize Autumn client with secret key from environment
const autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);

// Customer data
const customers = [
  { 
    customerId: 'user_test_001', 
    name: 'Bob Builder', 
    email: 'bob@example.com' 
  },
  { 
    customerId: 'user_test_002', 
    name: 'Carol Coder', 
    email: 'carol@example.com' 
  }
];

async function onboardCustomers() {
  try {
    console.log('Creating customers in parallel...');

    // Step 1: Create/sync customers in parallel using Promise.all
    const customerResults = await Promise.all(
      customers.map(customer =>
        autumn.customers.getOrCreate({
          id: customer.customerId,
          name: customer.name,
          email: customer.email
        })
      )
    );

    console.log('Customers created successfully:', customerResults);

    // Step 2: Attach "free" plan to both customers in parallel
    console.log('Attaching free plan to customers in parallel...');

    const attachResults = await Promise.all(
      customers.map(customer =>
        autumn.attach({
          customerId: customer.customerId,
          productId: 'free'
        })
      )
    );

    console.log('Plans attached successfully:', attachResults);

    // Step 3: Save results to JSON file
    const result = {
      customers: [
        { customerId: 'user_test_001', planAttached: true },
        { customerId: 'user_test_002', planAttached: true }
      ]
    };

    const resultPath = path.join('/home/user/myproject', 'onboard_result.json');
    fs.writeFileSync(resultPath, JSON.stringify(result, null, 2));

    console.log(`Results saved to ${resultPath}`);
    console.log('Result:', JSON.stringify(result, null, 2));

    return result;
  } catch (error) {
    console.error('Error during customer onboarding:', error);
    throw error;
  }
}

// Run the onboarding process
onboardCustomers()
  .then(() => {
    console.log('Onboarding completed successfully!');
    process.exit(0);
  })
  .catch((error) => {
    console.error('Onboarding failed:', error);
    process.exit(1);
  });

